// // This submodule controls the output enable signal of the bw_io_sstl_bscan module.
// It sets the oe signal high when either rcv_in or drv_oe is high.

module dram_pad_scan_jtag (
    input rcv_in,
    input drv_oe,
    output oe
);
    assign oe = ~rcv_in | ~drv_oe;
endmodule
module dram_pad_scan_jtag (
    input rcv_in,
    input drv_oe,
    output oe
);
    assign oe = rcv_in & drv_oe;
endmodule

